<?php
namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Models\Inventory\{InventoryLocation,InventoryStockOpname}; use App\Services\Inventory\InventoryLedgerService; use Illuminate\Http\Request;
class InventoryStockOpnameController extends Controller{public function index(){return view('inventory.stock-opnames.index',['opnames'=>InventoryStockOpname::with('location')->latest()->paginate(15)]);} public function create(){return view('inventory.stock-opnames.form',['locations'=>InventoryLocation::where('is_active',1)->get()]);} public function store(Request $r, InventoryLedgerService $svc){$op=$svc->createStockOpname($r->validate(['inventory_location_id'=>'required|exists:inventory_locations,id','opname_date'=>'required|date','notes'=>'nullable']),$r->user()->id);return redirect()->route('inventory.stock-opnames.show',$op)->with('status','Stock opname dibuat dari snapshot saldo.');} public function show(InventoryStockOpname $stockOpname){return view('inventory.stock-opnames.show',['opname'=>$stockOpname->load('location','lines.item','lines.condition')]);} public function update(Request $r, InventoryStockOpname $stockOpname){abort_if($stockOpname->status==='completed',403); foreach($r->input('lines',[]) as $id=>$line){$stockOpname->lines()->whereKey($id)->update(['physical_quantity'=>(int)$line['physical_quantity'],'difference_quantity'=>(int)$line['physical_quantity']-$stockOpname->lines()->find($id)->system_quantity,'notes'=>$line['notes']??null]);} return back()->with('status','Hasil fisik stock opname disimpan.');} public function post(InventoryStockOpname $stockOpname, InventoryLedgerService $svc){$svc->postStockOpname($stockOpname,auth()->id());return back()->with('status','Stock opname selesai dan koreksi tercatat.');}}
